// pages/LearnPage.jsx
// The core Learn page. Triggered when user clicks a topic.
// Fetches AI content from /api/learn and renders 6 structured sections:
//   Concept → Formulas → Shortcuts → Examples → Practice (MCQ) → Summary
// v2: Added Next / Previous topic navigation at the bottom.

import React, { useEffect, useState } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import { useLearn } from "../hooks/useLearn";
import { getTopicBySlug } from "../data/topicsData";

// ── Fixed ordered topic list ────────────────────────────────
// Names must match exactly what the API receives.
const TOPICS = [
  "Percentage",
  "Profit and Loss",
  "Ratio and Proportion",
  "Time and Work",
  "Simple Interest",
  "Compound Interest",
  "Time, Speed and Distance",
];

// "Profit and Loss" → "profit-and-loss"
function toSlug(name) {
  return name.toLowerCase().replace(/[,\s]+/g, "-");
}

// ── Loading skeleton ────────────────────────────────────────
function Skeleton() {
  return (
    <div className="space-y-4 animate-pulse">
      {[180, 120, 100, 160, 140, 110].map((h, i) => (
        <div
          key={i}
          className="rounded-2xl"
          style={{
            height: h,
            background: "rgba(255,255,255,0.04)",
            border: "1px solid rgba(255,255,255,0.06)",
          }}
        />
      ))}
    </div>
  );
}

// ── Section wrapper — consistent glass panel ────────────────
function Section({ label, icon, children, delay = 0 }) {
  return (
    <section
      className="glass animate-fade-up mb-5"
      style={{ animationDelay: `${delay}s` }}
    >
      <div
        className="flex items-center gap-2.5 px-6 py-3.5"
        style={{ borderBottom: "1px solid rgba(255,255,255,0.05)" }}
      >
        <span style={{ fontSize: "0.85rem" }}>{icon}</span>
        <span className="section-label">{label}</span>
      </div>
      <div className="px-6 py-5">{children}</div>
    </section>
  );
}

// ── Concept section ─────────────────────────────────────────
function ConceptSection({ concept }) {
  return (
    <Section label="Concept" icon="📖" delay={0.05}>
      <p className="text-slate-300 text-sm leading-relaxed">{concept}</p>
    </Section>
  );
}

// ── Formulas section — supports both string[] and {formula, explanation}[] ──
function FormulasSection({ formulas }) {
  return (
    <Section label="Key Formulas" icon="📐" delay={0.10}>
      <div className="space-y-3">
        {formulas.map((item, i) => {
          const formulaText = typeof item === "string" ? item : item.formula;
          const explanation = typeof item === "object" ? item.explanation : null;
          return (
            <div
              key={i}
              className="p-3.5 rounded-xl"
              style={{
                background: "rgba(99,102,241,0.07)",
                border: "1px solid rgba(99,102,241,0.14)",
              }}
            >
              <div className="flex items-start gap-3">
                <span
                  className="shrink-0 w-5 h-5 rounded-md flex items-center justify-center text-xs font-mono font-bold"
                  style={{ background: "rgba(99,102,241,0.25)", color: "#818cf8" }}
                >
                  {i + 1}
                </span>
                <code className="text-sm text-indigo-200 font-mono leading-relaxed">
                  {formulaText}
                </code>
              </div>
              {explanation && (
                <p className="mt-2 ml-8 text-xs text-slate-400 leading-relaxed">
                  {explanation}
                </p>
              )}
            </div>
          );
        })}
      </div>
    </Section>
  );
}

// ── Shortcuts section — supports both string[] and {trick, explanation}[] ──
function ShortcutsSection({ shortcuts }) {
  return (
    <Section label="Shortcuts & Tips" icon="⚡" delay={0.15}>
      <ul className="space-y-0 list-none m-0 p-0">
        {shortcuts.map((item, i) => {
          const trick = typeof item === "string" ? item : item.trick;
          const explanation = typeof item === "object" ? item.explanation : null;
          return (
            <li
              key={i}
              className="py-3"
              style={{ borderBottom: "1px solid rgba(255,255,255,0.04)" }}
            >
              <div className="flex items-start gap-3">
                <span className="shrink-0 text-sm" style={{ color: "#38bdf8" }}>›</span>
                <div>
                  <p className="text-sm text-slate-200 font-medium leading-relaxed">{trick}</p>
                  {explanation && (
                    <p className="mt-1 text-xs text-slate-400 leading-relaxed">{explanation}</p>
                  )}
                </div>
              </div>
            </li>
          );
        })}
      </ul>
    </Section>
  );
}

// ── Examples section ────────────────────────────────────────
function ExamplesSection({ examples }) {
  return (
    <Section label="Solved Examples" icon="✏️" delay={0.20}>
      <div className="space-y-6">
        {examples.map((ex, i) => (
          <div key={i}>
            {/* Question header */}
            <div className="flex items-start gap-3 mb-3">
              <span
                className="shrink-0 text-xs font-mono font-bold px-2 py-0.5 rounded-md mt-0.5"
                style={{
                  background: "rgba(56,189,248,0.12)",
                  color: "#38bdf8",
                  border: "1px solid rgba(56,189,248,0.20)",
                }}
              >
                Q{i + 1}
              </span>
              <p className="text-sm text-slate-200 font-medium leading-relaxed">
                {ex.question}
              </p>
            </div>

            {/* Step-by-step solution */}
            {Array.isArray(ex.steps) && ex.steps.length > 0 ? (
              <div className="ml-8 space-y-2 mb-3">
                {ex.steps.map((step, si) => (
                  <div
                    key={si}
                    className="px-4 py-2.5 rounded-xl text-sm text-slate-300 leading-relaxed"
                    style={{
                      background: "rgba(255,255,255,0.03)",
                      border: "1px solid rgba(255,255,255,0.06)",
                    }}
                  >
                    {step}
                  </div>
                ))}
              </div>
            ) : ex.solution ? (
              /* Fallback: legacy plain-text solution */
              <div
                className="ml-8 p-4 rounded-xl text-sm text-slate-400 leading-relaxed mb-3"
                style={{
                  background: "rgba(255,255,255,0.03)",
                  border: "1px solid rgba(255,255,255,0.06)",
                  whiteSpace: "pre-line",
                }}
              >
                {ex.solution}
              </div>
            ) : null}

            {/* Final answer badge */}
            {ex.finalAnswer && (
              <div
                className="ml-8 mb-2 inline-flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold"
                style={{
                  background: "rgba(52,211,153,0.10)",
                  border: "1px solid rgba(52,211,153,0.25)",
                  color: "#6ee7b7",
                }}
              >
                <span style={{ fontSize: "0.75rem" }}>✅</span>
                Final Answer: {ex.finalAnswer}
              </div>
            )}

            {/* Explanation */}
            {ex.explanation && (
              <div
                className="ml-8 mt-2 px-4 py-2.5 rounded-xl text-xs text-sky-300 leading-relaxed"
                style={{
                  background: "rgba(56,189,248,0.05)",
                  border: "1px solid rgba(56,189,248,0.12)",
                }}
              >
                💡 {ex.explanation}
              </div>
            )}

            {i < examples.length - 1 && (
              <hr className="mt-5 border-t border-white/5" />
            )}
          </div>
        ))}
      </div>
    </Section>
  );
}

// ── Option styles ────────────────────────────────────────────
const OPTION_NEUTRAL = {
  bg:     "rgba(255,255,255,0.04)",
  border: "rgba(255,255,255,0.08)",
  text:   "#94a3b8",
};

const CORRECT_STYLE = {
  bg:     "rgba(52,211,153,0.15)",
  border: "rgba(52,211,153,0.40)",
  text:   "#6ee7b7",
};

// ── MCQ Practice item ────────────────────────────────────────
function PracticeItem({ item, index }) {
  const [selected, setSelected] = useState(null);
  const [revealed, setRevealed] = useState(false);

  const handleSelect = (key) => {
    if (revealed) return;
    setSelected(key);
  };

  const handleReveal = () => {
    if (!selected) return;
    setRevealed(true);
  };

  const handleReset = () => {
    setSelected(null);
    setRevealed(false);
  };

  return (
    <div
      className="py-5"
      style={{ borderBottom: "1px solid rgba(255,255,255,0.05)" }}
    >
      {/* Question */}
      <div className="flex items-start gap-3 mb-4">
        <span
          className="shrink-0 text-xs font-mono font-bold px-2 py-0.5 rounded-md mt-0.5"
          style={{
            background: "rgba(99,102,241,0.12)",
            color: "#a5b4fc",
            border: "1px solid rgba(99,102,241,0.20)",
          }}
        >
          Q{index + 1}
        </span>
        <p className="text-sm text-slate-200 font-medium leading-relaxed">
          {item.question}
        </p>
      </div>

      {/* Options */}
      <div className="ml-8 grid grid-cols-1 gap-2 mb-3">
        {Object.entries(item.options).map(([key, value]) => {
          const isCorrect  = key === item.correctAnswer;
          const isSelected = key === selected;

          let style = {
            background: OPTION_NEUTRAL.bg,
            border:     `1px solid ${OPTION_NEUTRAL.border}`,
            color:      OPTION_NEUTRAL.text,
          };

          if (revealed) {
            if (isCorrect) {
              style = {
                background: CORRECT_STYLE.bg,
                border:     `1px solid ${CORRECT_STYLE.border}`,
                color:      CORRECT_STYLE.text,
              };
            } else if (isSelected && !isCorrect) {
              style = {
                background: "rgba(239,68,68,0.12)",
                border:     "1px solid rgba(239,68,68,0.35)",
                color:      "#fca5a5",
              };
            }
          } else if (isSelected) {
            style = {
              background: "rgba(99,102,241,0.18)",
              border:     "1px solid rgba(99,102,241,0.45)",
              color:      "#c7d2fe",
            };
          }

          return (
            <button
              key={key}
              onClick={() => handleSelect(key)}
              disabled={revealed}
              className="flex items-center gap-3 w-full text-left px-4 py-2.5 rounded-xl text-sm transition-all duration-200"
              style={{ ...style, cursor: revealed ? "default" : "pointer" }}
            >
              <span
                className="shrink-0 w-5 h-5 rounded-md flex items-center justify-center text-xs font-mono font-bold"
                style={{ background: "rgba(255,255,255,0.07)", color: style.color }}
              >
                {key}
              </span>
              <span className="leading-relaxed">{value}</span>
              {revealed && isCorrect && (
                <span className="ml-auto text-xs font-bold" style={{ color: "#6ee7b7" }}>✓ Correct</span>
              )}
              {revealed && isSelected && !isCorrect && (
                <span className="ml-auto text-xs font-bold" style={{ color: "#fca5a5" }}>✗ Wrong</span>
              )}
            </button>
          );
        })}
      </div>

      {/* Action buttons */}
      <div className="ml-8 flex items-center gap-2">
        {!revealed ? (
          <button
            onClick={handleReveal}
            disabled={!selected}
            className="text-xs px-3 py-1.5 rounded-lg transition-all duration-200"
            style={{
              background: selected ? "rgba(99,102,241,0.20)" : "rgba(255,255,255,0.04)",
              color:      selected ? "#a5b4fc" : "#475569",
              border:     selected ? "1px solid rgba(99,102,241,0.35)" : "1px solid rgba(255,255,255,0.07)",
              cursor:     selected ? "pointer" : "not-allowed",
            }}
          >
            {selected ? "Check Answer" : "Select an option first"}
          </button>
        ) : (
          <button
            onClick={handleReset}
            className="text-xs px-3 py-1.5 rounded-lg transition-all duration-200"
            style={{
              background: "rgba(255,255,255,0.05)",
              color:      "#64748b",
              border:     "1px solid rgba(255,255,255,0.08)",
              cursor:     "pointer",
            }}
          >
            ↺ Try Again
          </button>
        )}
      </div>

      {/* Explanation after reveal */}
      {revealed && (
        <div
          className="ml-8 mt-3 px-4 py-3 rounded-xl text-sm leading-relaxed animate-fade-in"
          style={{
            background: "rgba(255,255,255,0.04)",
            border:     "1px solid rgba(255,255,255,0.08)",
          }}
        >
          <p className="text-slate-400">{item.explanation}</p>
        </div>
      )}
    </div>
  );
}

