// ── Topic Navigation Bar ─────────────────────────────────────
// Renders at the bottom of the page.
// Previous is disabled on first topic.
// Next is replaced by a completion message on the last topic.
function TopicNav({ currentIndex, onNavigate }) {
  const isFirst = currentIndex === 0;
  const isLast  = currentIndex === TOPICS.length - 1;

  const activeStyle = {
    fontSize:     "0.8rem",
    fontFamily:   "Poppins, sans-serif",
    fontWeight:   500,
    padding:      "9px 18px",
    borderRadius: "10px",
    border:       "none",
    cursor:       "pointer",
    background:   "linear-gradient(135deg, #6366f1, #4f46e5)",
    color:        "#fff",
    boxShadow:    "0 0 14px rgba(99,102,241,0.30)",
    transition:   "transform 0.15s, box-shadow 0.2s",
    display:      "inline-flex",
    alignItems:   "center",
    gap:          "6px",
  };

  const disabledStyle = {
    fontSize:     "0.8rem",
    fontFamily:   "Poppins, sans-serif",
    fontWeight:   500,
    padding:      "9px 18px",
    borderRadius: "10px",
    border:       "1px solid rgba(255,255,255,0.06)",
    cursor:       "not-allowed",
    background:   "rgba(255,255,255,0.04)",
    color:        "#334155",
    display:      "inline-flex",
    alignItems:   "center",
    gap:          "6px",
  };

  return (
    <div
      className="mt-8 pt-6"
      style={{ borderTop: "1px solid rgba(255,255,255,0.06)" }}
    >
      <div className="flex items-center justify-between gap-4 flex-wrap">

        {/* ── Previous ── */}
        <button
          onClick={() => !isFirst && onNavigate(currentIndex - 1)}
          disabled={isFirst}
          style={isFirst ? disabledStyle : activeStyle}
          onMouseEnter={(e) => {
            if (!isFirst) e.currentTarget.style.transform = "translateY(-1px)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "none";
          }}
        >
          ← Previous Topic
        </button>

        {/* ── Position counter ── */}
        <span className="text-xs font-mono" style={{ color: "#475569" }}>
          {currentIndex + 1} / {TOPICS.length}
        </span>

        {/* ── Next or completion message ── */}
        {isLast ? (
          <span
            className="text-xs font-mono px-3 py-2 rounded-lg"
            style={{
              background: "rgba(34,197,94,0.08)",
              color:      "#86efac",
              border:     "1px solid rgba(34,197,94,0.18)",
            }}
          >
            ✓ You've completed all topics
          </span>
        ) : (
          <button
            onClick={() => onNavigate(currentIndex + 1)}
            style={activeStyle}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = "translateY(-1px)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "none";
            }}
          >
            Next Topic →
          </button>
        )}
      </div>
    </div>
  );
}

// ── Main LearnPage ──────────────────────────────────────────
export default function LearnPage() {
  const { topicName } = useParams();
  const navigate      = useNavigate();
  const localTopic    = getTopicBySlug(topicName);
  const displayName   = localTopic?.name || topicName?.replace(/-/g, " ");

  // Find this topic's position in the TOPICS array (case-insensitive)
  const currentIndex = TOPICS.findIndex(
    (t) => t.toLowerCase() === displayName?.toLowerCase()
  );

  const { fetchLearnContent, loading, error } = useLearn();
  const [content,  setContent]  = useState(null);
  const [retryKey, setRetryKey] = useState(0);

  // Fetch whenever topic or retryKey changes
  useEffect(() => {
    if (!displayName) return;
    setContent(null);                                 // clear stale content
    window.scrollTo({ top: 0, behavior: "smooth" }); // scroll to top on topic switch
    fetchLearnContent(displayName).then((data) => {
      if (data) setContent(data);
    });
  }, [displayName, retryKey]); // eslint-disable-line

  const handleRetry = () => setRetryKey((k) => k + 1);

  // Navigate by index — React Router, no page reload
  const handleNavigate = (index) => {
    navigate(`/topic/${toSlug(TOPICS[index])}`);
  };

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">

      {/* Breadcrumb */}
      <div className="flex items-center gap-2 text-xs text-slate-500 mb-8 animate-fade-in">
        <Link to="/" className="hover:text-slate-300 transition-colors no-underline">
          Home
        </Link>
        <span>/</span>
        <span className="text-slate-300">{displayName}</span>
      </div>

      {/* Page title */}
      <div className="mb-8 animate-fade-up">
        <h1
          className="text-2xl font-bold text-white mb-1"
          style={{ letterSpacing: "-0.01em" }}
        >
          {displayName}
        </h1>
        {localTopic && (
          <span className="section-label" style={{ color: "#6366f1" }}>
            {localTopic.category}
          </span>
        )}
      </div>

      {/* ── States ── */}
      {loading && <Skeleton />}

      {!loading && error && (
        <ErrorPanel message={error} onRetry={handleRetry} />
      )}

      {!loading && !error && content && (
        <>
          <ConceptSection   concept={content.concept} />
          <FormulasSection  formulas={content.formulas} />
          <ShortcutsSection shortcuts={content.shortcuts} />
          <ExamplesSection  examples={content.examples} />
          <PracticeSection  practice={content.practice} />
          <SummarySection   summary={content.summary} />
        </>
      )}

      {/* Topic navigation — only shown when topic exists in the list */}
      {currentIndex !== -1 && (
        <TopicNav
          currentIndex={currentIndex}
          onNavigate={handleNavigate}
        />
      )}

      {/* Back link */}
      <div className="mt-6">
        <Link
          to="/"
          className="text-xs text-slate-500 hover:text-slate-300 transition-colors no-underline"
        >
          ← Back to all topics
        </Link>
      </div>

      <div className="h-16" />
    </main>
  );
}
